script:
frappe.ui.form.on('Employee', {
  designation: function(frm) {
    if (!frm.doc.designation) {
      frm.set_value('za_occupational_level', '');
      return;
    }

    frappe.db.get_value('Designation', frm.doc.designation, 'custom_occupational_level')
      .then(r => {
        const occupational_level = r.message ? r.message.custom_occupational_level : null;
        frm.set_value('za_occupational_level', occupational_level || '');
      });
  }
});
